#!/usr/bin/env node
/**
 * k6 load-test route coverage audit.
 *
 * Reads docs/routes.txt (generated by `pnpm routes:catalog`) and checks which
 * routes are exercised by at least one k6 scenario file under
 * src/tests/load/k6/scenarios/. Prints a coverage table and exits non-zero
 * when uncovered AUTH/PERM routes fall below the threshold.
 *
 * What counts as "covered": the scenario file contains the static path prefix
 * (everything before the first path parameter). For example:
 *   /api/v1/tenancy/organizations/:id/settings
 *     → looks for "/organizations/" AND "/settings" in the same file.
 *
 * What is excluded from the required set:
 *   - ROLE: super_admin / admin — requires elevated JWT not in the pool
 *   - TOKEN routes (internal/ops)
 *   - PUBLIC infrastructure routes (OAuth, magic-link, WebAuthn, Stripe webhook,
 *     health, email verify, password reset) that are not realistic load targets
 *
 * Usage:
 *   node tooling/ci/check-load-coverage.mjs
 *   node tooling/ci/check-load-coverage.mjs --report-only   # never exits non-zero
 *   node tooling/ci/check-load-coverage.mjs --threshold 60  # override minimum %
 */
import { readFileSync, readdirSync } from 'node:fs';
import { join, resolve } from 'node:path';

const ROOT = resolve(new URL('.', import.meta.url).pathname, '../..');
const ROUTES_FILE = join(ROOT, 'docs/routes.txt');
const SCENARIOS_DIR = join(ROOT, 'src/tests/load/k6/scenarios');
const DEFAULT_THRESHOLD = 50; // % of required routes that must appear in ≥1 scenario

// --------------------------------------------------------------------------
// Args
// --------------------------------------------------------------------------

const args = process.argv.slice(2);
const reportOnly = args.includes('--report-only');
const thresholdIdx = args.indexOf('--threshold');
const threshold = thresholdIdx !== -1 ? Number(args[thresholdIdx + 1]) : DEFAULT_THRESHOLD;

// --------------------------------------------------------------------------
// Parse routes.txt
// --------------------------------------------------------------------------

const ROUTE_LINE_RE = /^\s+(GET|POST|PUT|PATCH|DELETE)\s+(\/[^\s]+)\s+(.*)/;

function parseRoutes(content) {
  return content
    .split('\n')
    .map((line) => {
      const match = ROUTE_LINE_RE.exec(line);
      if (!match) return null;
      return { method: match[1], path: match[2], auth: match[3].trim() };
    })
    .filter(Boolean);
}

/** Returns true for routes we don't require k6 coverage for. */
function isExcluded({ auth, path }) {
  if (auth.startsWith('ROLE:')) return true; // admin / super_admin only
  if (auth.startsWith('TOKEN:')) return true; // internal/ops
  // PUBLIC routes that are infrastructure / device-flow and not realistic load targets
  const publicSkip = [
    '/auth/oauth',
    '/auth/magic-link',
    '/auth/email/verify',
    '/auth/mfa/login',
    '/auth/password/forgot',
    '/auth/password/reset',
    '/auth/webauthn',
    '/auth/refresh',
    '/billing/stripe/webhook',
    '/billing/webhook',
    '/tenancy/invitations/',
    '/livez',
    '/readyz',
    '/mcp',
  ];
  if (auth === 'PUBLIC' && publicSkip.some((p) => path.includes(p))) return true;
  return false;
}

// --------------------------------------------------------------------------
// Load scenario source files
// --------------------------------------------------------------------------

function loadScenarios() {
  return readdirSync(SCENARIOS_DIR)
    .filter((f) => f.endsWith('.js'))
    .map((f) => ({ name: f, content: readFileSync(join(SCENARIOS_DIR, f), 'utf8') }));
}

// --------------------------------------------------------------------------
// Heuristic coverage check
//
// Split the path at the first dynamic segment (:param). A route is "covered"
// if any scenario file contains the static prefix AND the last static suffix
// segment (when one exists after the params).
//
// Examples:
//   /api/v1/users/me               → must contain "/users/me"
//   /api/v1/organizations/:id      → must contain "/organizations/"
//   /api/v1/organizations/:id/settings → prefix "/organizations/" + suffix "settings"
// --------------------------------------------------------------------------

function staticSegments(path) {
  const parts = path.split('/').filter(Boolean);
  const firstParam = parts.findIndex((p) => p.startsWith(':'));
  const prefix = (firstParam === -1 ? parts : parts.slice(0, firstParam)).join('/');
  const tail =
    firstParam === -1 ? [] : parts.slice(firstParam + 1).filter((p) => !p.startsWith(':'));
  return {
    prefix: '/' + prefix,
    suffix: tail.length > 0 ? tail[tail.length - 1] : null,
  };
}

function isCovered(route, scenarios) {
  const { prefix, suffix } = staticSegments(route.path);
  // k6 scenarios write `${API_PREFIX}/users/me` — the `/api/v1` part never
  // appears as a literal string. Strip the versioned prefix so we match on
  // the domain-level path segment instead (e.g. `/users/me`, `/notify/...`).
  const strippedPrefix = prefix.replace(/^\/api\/v\d+/, '');
  return scenarios.some(({ content }) => {
    const prefixFound =
      content.includes(prefix) || (strippedPrefix.length > 1 && content.includes(strippedPrefix));
    if (!prefixFound) return false;
    if (suffix && !content.includes(`/${suffix}`)) return false;
    return true;
  });
}

// --------------------------------------------------------------------------
// Main
// --------------------------------------------------------------------------

let routesContent;
try {
  routesContent = readFileSync(ROUTES_FILE, 'utf8');
} catch {
  console.error(`check-load-coverage: cannot read ${ROUTES_FILE} — run pnpm routes:catalog first`);
  process.exit(reportOnly ? 0 : 1);
}

const allRoutes = parseRoutes(routesContent);
const required = allRoutes.filter((r) => !isExcluded(r));
const scenarios = loadScenarios();
const covered = required.filter((r) => isCovered(r, scenarios));
const uncovered = required.filter((r) => !isCovered(r, scenarios));
const pct = required.length === 0 ? 100 : Math.round((covered.length / required.length) * 100);

// --------------------------------------------------------------------------
// Report
// --------------------------------------------------------------------------

const GRN = '\x1b[32m';
const YLW = '\x1b[33m';
const RED = '\x1b[31m';
const DIM = '\x1b[2m';
const RST = '\x1b[0m';

console.log('\n─────────────────────────────────────────────────────────');
console.log('  k6 Load-test Route Coverage');
console.log('─────────────────────────────────────────────────────────');
console.log(`  Total routes       : ${allRoutes.length}`);
console.log(`  Required (testable): ${required.length}`);
console.log(`  Covered            : ${covered.length}  ${GRN}✓${RST}`);
console.log(
  `  Uncovered          : ${uncovered.length}  ${uncovered.length > 0 ? YLW + '⚠' : GRN + '✓'}${RST}`,
);
console.log(
  `  Coverage           : ${pct >= threshold ? GRN : RED}${pct}%${RST}  (threshold: ${threshold}%)`,
);
console.log('─────────────────────────────────────────────────────────\n');

if (uncovered.length > 0) {
  console.log(`${YLW}Uncovered routes — add to a k6 scenario to improve coverage:${RST}`);
  for (const r of uncovered) {
    console.log(`  ${DIM}${r.method.padEnd(7)}${RST} ${r.path}  ${DIM}${r.auth}${RST}`);
  }
  console.log('');
}

if (covered.length > 0) {
  console.log(`${GRN}Covered routes:${RST}`);
  for (const r of covered) {
    console.log(`  ${DIM}${r.method.padEnd(7)}${RST} ${r.path}`);
  }
  console.log('');
}

// --------------------------------------------------------------------------
// Exit
// --------------------------------------------------------------------------

if (pct < threshold) {
  if (reportOnly) {
    console.log(
      `${YLW}⚠ check-load-coverage: ${pct}% < ${threshold}% — below threshold (report-only, not failing)${RST}\n`,
    );
  } else {
    console.error(
      `${RED}✗ check-load-coverage: ${pct}% < threshold ${threshold}% — failing build.${RST}`,
    );
    console.error(
      `  Add uncovered routes to a k6 scenario, lower --threshold, or use --report-only.\n`,
    );
    process.exit(1);
  }
} else {
  console.log(`${GRN}✓ check-load-coverage: ${pct}% ≥ ${threshold}% — OK${RST}\n`);
}
